import React, { useState } from 'react';
import StartPage from './components/StartPage';
import RulesPage from './components/RulesPage';
import QuizPage from './components/QuizPage';
import ResultPage from './components/ResultPage';

function App() {
  const [currentPage, setCurrentPage] = useState('start');
  const [quizId, setQuizId] = useState(null);
  const [teamInfo, setTeamInfo] = useState(null);
  const [result, setResult] = useState(null);

  const handleQuizStart = (id, info) => {
    console.log('Quiz started:', id, info);
    setQuizId(id);
    setTeamInfo(info);
    setCurrentPage('rules');
  };

  const handleRulesAccept = () => {
    console.log('Rules accepted, starting quiz');
    setCurrentPage('quiz');
  };

  const handleQuizSubmit = (quizResult) => {
    console.log('Quiz submitted:', quizResult);
    setResult(quizResult);
    setCurrentPage('result');
  };

  const handleBackToStart = () => {
    console.log('Returning to start page');
    setCurrentPage('start');
    setQuizId(null);
    setTeamInfo(null);
    setResult(null);
  };

  // Render based on current page
  const renderPage = () => {
    switch(currentPage) {
      case 'start':
        return <StartPage onQuizStart={handleQuizStart} />;

      case 'rules':
        // Only show rules page if we have quizId and teamInfo
        if (quizId && teamInfo) {
          return <RulesPage onAccept={handleRulesAccept} />;
        } else {
          // If no quiz info, go back to start
          setCurrentPage('start');
          return null;
        }

      case 'quiz':
        // Only show quiz page if we have quizId and teamInfo
        if (quizId && teamInfo) {
          return (
            <QuizPage
              quizId={quizId}
              teamInfo={teamInfo}
              onSubmit={handleQuizSubmit}
              onTimeout={() => console.log('Time up')}
            />
          );
        } else {
          // If no quiz info, go back to start
          setCurrentPage('start');
          return null;
        }

      case 'result':
        // Only show result page if we have result
        if (result && teamInfo) {
          return (
            <ResultPage 
              result={result} 
              teamInfo={teamInfo} 
              onRestart={handleBackToStart}
            />
          );
        } else {
          // If no result, go back to start
          setCurrentPage('start');
          return null;
        }

      default:
        return <StartPage onQuizStart={handleQuizStart} />;
    }
  };

  return (
    <div style={{ 
      height: '100vh', 
      width: '100vw',
      backgroundColor: '#ffffff',
      overflow: 'auto'
    }}>
      {renderPage()}
    </div>
  );
}

export default App;
